(0, 'document', '变量与数据类型', '{"content":"# 变量与数据类型\n\n## 变量\n变量是存储数据的容器，必须先声明后使用。\n\n## 基本数据类型\n| 类型 | 大小 | 示例 |\n|------|------|------|\n| int | 4字节 | int age = 20; |\n| double | 8字节 | double price = 9.99; |\n| char | 2字节 | char grade = A; |\n| boolean | 1字节 | boolean isTrue = true; |\n\n## 引用数据类型\n- String：字符串\n- Array：数组\n- Class：类\n\n## 变量命名规则\n1. 以字母、下划线或$开头\n2. 不能使用关键字\n3. 驼峰命名法"}', 'L1', NOW()),

(0, 'quiz', '变量与数据类型', '{"questions":[{"content":"以下哪个是合法的变量名？","type":"CHOICE","difficulty":"EASY","options":[{"content":"123abc","isCorrect":false},{"content":"_name","isCorrect":true},{"content":"class","isCorrect":false},{"content":"my-var","isCorrect":false}],"analysis":"变量名不能以数字开头，不能使用关键字，不能包含连字符"},{"content":"int类型占多少字节？","type":"CHOICE","difficulty":"EASY","options":[{"content":"2字节","isCorrect":false},{"content":"4字节","isCorrect":true},{"content":"8字节","isCorrect":false},{"content":"16字节","isCorrect":false}],"analysis":"int是32位整数，占4字节"},{"content":"以下哪个不是基本数据类型？","type":"CHOICE","difficulty":"EASY","options":[{"content":"int","isCorrect":false},{"content":"boolean","isCorrect":false},{"content":"String","isCorrect":true},{"content":"char","isCorrect":false}],"analysis":"String是引用类型，不是基本数据类型"}]}', 'L1', NOW()),

