(0, 'document', '运算符与表达式', '{"content":"# 运算符与表达式\n\n## 算术运算符\n- +：加法\n- -：减法\n- *：乘法\n- /：除法\n- %：取模\n\n## 比较运算符\n- ==：等于\n- !=：不等于\n- >：大于\n- <：小于\n- >=：大于等于\n- <=：小于等于\n\n## 逻辑运算符\n- &&：与\n- ||：或\n- !：非\n\n## 赋值运算符\n- =：赋值\n- +=：加等于\n- -=：减等于"}', 'L1', NOW()),

(0, 'quiz', '运算符与表达式', '{"questions":[{"content":"5 % 2 的结果是？","type":"CHOICE","difficulty":"EASY","options":[{"content":"2","isCorrect":false},{"content":"2.5","isCorrect":false},{"content":"1","isCorrect":true},{"content":"0","isCorrect":false}],"analysis":"%是取模运算，5除以2余1"},{"content":"true && false 的结果是？","type":"CHOICE","difficulty":"EASY","options":[{"content":"true","isCorrect":false},{"content":"false","isCorrect":true},{"content":"null","isCorrect":false},{"content":"编译错误","isCorrect":false}],"analysis":"&&是与运算，两个都为true才为true"},{"content":"以下哪个不是Java运算符？","type":"CHOICE","difficulty":"EASY","options":[{"content":"+=","isCorrect":false},{"content":"&&","isCorrect":false},{"content":"**","isCorrect":true},{"content":"!=","isCorrect":false}],"analysis":"**不是Java运算符，幂运算用Math.pow()"}]}', 'L1', NOW()),

